package br.gov.siscomex.portalunico.anex.api;

import br.gov.siscomex.portalunico.anex.model.ExceptionCover;
import br.gov.siscomex.portalunico.anex.model.ParametroAnexarDocumentoPorOperacao;
import br.gov.siscomex.portalunico.anex.model.RetornoAnexarDocumento;
import br.gov.siscomex.portalunico.anex.model.RetornoConsultarDocumentoPorOperacao;
import br.gov.siscomex.portalunico.anex.model.RetornoConsultarPalavrasChave;
import br.gov.siscomex.portalunico.anex.model.RetornoConsultarTiposDocumentoComTiposDossie;
